echo -e "${CYAN}9) ${GREEN}–Θ–¥–Α–Μ–Η―²―¨ ${NC}βÜ£${GREEN} ―É―¹―²–Α–Ϋ–Ψ–≤–Η―²―¨ ${NC}βÜ£${GREEN} –Ϋ–Α―¹―²―Ä–Ψ–Η―²―¨${NC} Zapret\n${CYAN}0) ${GREEN}–Γ–Η―¹―²–Β–Φ–Ϋ–Ψ–Β –Φ–Β–Ϋ―é${NC}\n${CYAN}s) ${GREEN}$str_stp_zpr ${NC}Zapret" ; echo -ne "${CYAN}Enter) ${GREEN}–£―΄―Ö–Ψ–¥${NC}\n\n${YELLOW}–£―΄–±–Β―Ä–Η―²–Β –Ω―É–Ϋ–Κ―²:${NC} " && read choice
